// // This module converts a 4-bit Gray code to a 4-bit binary code
module bin_to_gray(
    input   [3:0]       bin,
    output  [3:0]       gray
);

// Binary to Gray code conversion logic
assign gray[3] = bin[3];
assign gray[2] = bin[3] ^ bin[2];
assign gray[1] = bin[2] ^ bin[1];
assign gray[0] = bin[1] ^ bin[0];

endmodule
